public static String getBaseName(final Path path) {
        // TODO Use Commons IO 2.16.0
        if (path == null) {
            return null;
        }
        final Path fileName = path.getFileName();
        return fileName != null ? FilenameUtils.removeExtension(fileName.toString()) : null;
    }

